int totalPoints = 0;

for (int day = 1; day <= 3; day++)
{
    totalPoints += 10;
    Console.WriteLine("Day completed");
}

if (totalPoints >= 30)
{
    Console.WriteLine("Reward unlocked");
}
else
{
    Console.WriteLine("More points needed");
}

Console.WriteLine(totalPoints);

